INSERT INTO assessment_questions (id, pillar, subcategory, subcategory_label, text, help_text, weight, sort_order, options, status) VALUES
  ('e-carbon-1', 'environmental', 'carbon-emissions', 'Carbon & Emissions', 'Does your organization measure its greenhouse gas (GHG) emissions?', 'This includes Scope 1 (direct), Scope 2 (energy), and Scope 3 (value chain) emissions.', 3, 0, '[{"label":"No measurement","value":0,"description":"We have not started measuring emissions"},{"label":"Informal estimates","value":1,"description":"We have rough estimates but no formal process"},{"label":"Scope 1 & 2 measured","value":2,"description":"We formally track direct and energy emissions"},{"label":"All scopes measured","value":3,"description":"We measure Scope 1, 2, and some Scope 3 categories"},{"label":"Comprehensive tracking","value":4,"description":"Full Scope 1-3 measurement with third-party verification"}]'::jsonb, 'active'),
  ('e-carbon-2', 'environmental', 'carbon-emissions', 'Carbon & Emissions', 'Has your organization set emissions reduction targets?', 'Targets may be aligned with frameworks like the Science Based Targets initiative (SBTi).', 2, 1, '[{"label":"No targets","value":0,"description":"We have not set any reduction targets"},{"label":"Informal goals","value":1,"description":"We have general aspirations but no formal targets"},{"label":"Internal targets","value":2,"description":"We have set internal reduction targets with timelines"},{"label":"Science-aligned targets","value":3,"description":"Targets are aligned with climate science (e.g., SBTi)"},{"label":"Validated & on track","value":4,"description":"Externally validated targets with demonstrated progress"}]'::jsonb, 'active'),
  ('e-energy-1', 'environmental', 'energy-management', 'Energy Management', 'What percentage of your organization''s energy comes from renewable sources?', NULL, 2, 2, '[{"label":"None / Unknown","value":0,"description":"We don''t track renewable energy usage"},{"label":"Under 25%","value":1,"description":"Some renewable energy but mostly conventional"},{"label":"25-50%","value":2,"description":"Significant renewable energy procurement"},{"label":"50-75%","value":3,"description":"Majority renewable energy"},{"label":"Over 75%","value":4,"description":"Predominantly or fully powered by renewables"}]'::jsonb, 'active'),
  ('e-energy-2', 'environmental', 'energy-management', 'Energy Management', 'Does your organization have an energy efficiency improvement program?', NULL, 2, 3, '[{"label":"No program","value":0,"description":"No formal energy efficiency initiatives"},{"label":"Ad hoc efforts","value":1,"description":"Occasional efficiency upgrades without a plan"},{"label":"Basic program","value":2,"description":"Defined program with some efficiency targets"},{"label":"Comprehensive program","value":3,"description":"Systematic program with annual targets and reporting"},{"label":"Industry-leading","value":4,"description":"Certified energy management system (e.g., ISO 50001)"}]'::jsonb, 'active'),
  ('e-waste-1', 'environmental', 'waste-circular-economy', 'Waste & Circular Economy', 'How does your organization manage waste and recycling?', NULL, 2, 4, '[{"label":"No tracking","value":0,"description":"Waste is not tracked or managed systematically"},{"label":"Basic recycling","value":1,"description":"Standard recycling bins but no formal program"},{"label":"Waste reduction plan","value":2,"description":"Formal waste reduction targets and recycling programs"},{"label":"Circular practices","value":3,"description":"Active circular economy practices and high diversion rates"},{"label":"Zero-waste goal","value":4,"description":"Near-zero waste to landfill with circular design principles"}]'::jsonb, 'active'),
  ('e-waste-2', 'environmental', 'waste-circular-economy', 'Waste & Circular Economy', 'Does your organization consider environmental impact in product/service design?', NULL, 1, 5, '[{"label":"Not considered","value":0,"description":"Environmental impact is not part of design decisions"},{"label":"Occasionally","value":1,"description":"Sometimes considered for certain products"},{"label":"Regularly assessed","value":2,"description":"Environmental factors are part of our design process"},{"label":"Life-cycle analysis","value":3,"description":"We conduct life-cycle assessments for key products"},{"label":"Eco-design standard","value":4,"description":"Systematic eco-design across all products/services"}]'::jsonb, 'active'),
  ('e-water-1', 'environmental', 'water-resources', 'Water Resources', 'Does your organization track and manage water consumption?', NULL, 1, 6, '[{"label":"Not tracked","value":0,"description":"Water usage is not monitored"},{"label":"Basic monitoring","value":1,"description":"We track total water use but don''t actively manage it"},{"label":"Reduction targets","value":2,"description":"We track usage and have set reduction targets"},{"label":"Comprehensive management","value":3,"description":"Water stewardship program with efficiency measures"},{"label":"Water positive","value":4,"description":"Restoring or replenishing more water than we use"}]'::jsonb, 'active'),
  ('e-water-2', 'environmental', 'water-resources', 'Water Resources', 'Has your organization assessed water-related risks in your operations or supply chain?', NULL, 1, 7, '[{"label":"No assessment","value":0,"description":"Water risks have not been evaluated"},{"label":"Awareness only","value":1,"description":"We''re aware of water risks but haven''t formally assessed them"},{"label":"Initial assessment","value":2,"description":"Conducted a basic water risk assessment"},{"label":"Detailed assessment","value":3,"description":"Comprehensive assessment including supply chain"},{"label":"Active mitigation","value":4,"description":"Ongoing risk monitoring with mitigation strategies in place"}]'::jsonb, 'active'),
  ('e-policy-1', 'environmental', 'environmental-policy', 'Environmental Policy & Compliance', 'Does your organization have a formal environmental policy or management system?', NULL, 2, 8, '[{"label":"No policy","value":0,"description":"No written environmental policy exists"},{"label":"Informal guidelines","value":1,"description":"General awareness but no formal policy"},{"label":"Written policy","value":2,"description":"Formal environmental policy approved by leadership"},{"label":"Management system","value":3,"description":"Environmental management system with regular audits"},{"label":"Certified EMS","value":4,"description":"Certified system (e.g., ISO 14001) with continuous improvement"}]'::jsonb, 'active'),
  ('e-policy-2', 'environmental', 'environmental-policy', 'Environmental Policy & Compliance', 'Does your organization publicly report on environmental performance?', NULL, 2, 9, '[{"label":"No reporting","value":0,"description":"No environmental reporting is done"},{"label":"Internal only","value":1,"description":"Environmental data shared internally only"},{"label":"Basic public report","value":2,"description":"Some environmental data published on website or reports"},{"label":"Framework-aligned","value":3,"description":"Reporting aligned with GRI, CDP, or similar frameworks"},{"label":"Assured reporting","value":4,"description":"Third-party assured sustainability report published annually"}]'::jsonb, 'active'),
  ('s-labor-1', 'social', 'labor-practices', 'Labor Practices & Working Conditions', 'How does your organization ensure fair wages and working conditions?', NULL, 3, 10, '[{"label":"Minimum compliance","value":0,"description":"We meet legal minimums only"},{"label":"Above minimum","value":1,"description":"We generally pay above minimum wage"},{"label":"Living wage commitment","value":2,"description":"Committed to living wages for all employees"},{"label":"Comprehensive program","value":3,"description":"Living wages plus benefits, flexibility, and wellness programs"},{"label":"Best-in-class","value":4,"description":"Recognized as an employer of choice with leading compensation"}]'::jsonb, 'active'),
  ('s-labor-2', 'social', 'labor-practices', 'Labor Practices & Working Conditions', 'Does your organization measure and report on employee health and safety?', NULL, 2, 11, '[{"label":"No tracking","value":0,"description":"H&S metrics are not tracked"},{"label":"Basic compliance","value":1,"description":"We track incidents as legally required"},{"label":"Proactive program","value":2,"description":"H&S program with prevention focus and regular training"},{"label":"Comprehensive system","value":3,"description":"Formal OHS management system with targets"},{"label":"Certified system","value":4,"description":"Certified H&S system (e.g., ISO 45001) with zero-harm goal"}]'::jsonb, 'active'),
  ('s-dei-1', 'social', 'diversity-equity-inclusion', 'Diversity, Equity & Inclusion', 'Does your organization have a formal DEI strategy with measurable goals?', NULL, 2, 12, '[{"label":"No strategy","value":0,"description":"DEI is not formally addressed"},{"label":"General statement","value":1,"description":"We have a diversity statement but no formal program"},{"label":"Active program","value":2,"description":"DEI program with training and awareness initiatives"},{"label":"Measurable goals","value":3,"description":"DEI strategy with specific targets and progress tracking"},{"label":"Embedded in culture","value":4,"description":"DEI is embedded in all processes with transparent reporting"}]'::jsonb, 'active'),
  ('s-dei-2', 'social', 'diversity-equity-inclusion', 'Diversity, Equity & Inclusion', 'Does your organization conduct pay equity analysis and report on diversity metrics?', NULL, 2, 13, '[{"label":"No analysis","value":0,"description":"We don''t analyze pay equity or diversity metrics"},{"label":"Informal review","value":1,"description":"Occasional informal reviews of pay and diversity"},{"label":"Annual analysis","value":2,"description":"Annual pay equity analysis with internal reporting"},{"label":"Public reporting","value":3,"description":"Regular analysis with public disclosure of key metrics"},{"label":"Third-party audited","value":4,"description":"Independent pay equity audit with full public transparency"}]'::jsonb, 'active'),
  ('s-supply-1', 'social', 'supply-chain-responsibility', 'Supply Chain Responsibility', 'Does your organization assess ESG practices in your supply chain?', NULL, 2, 14, '[{"label":"No assessment","value":0,"description":"We don''t evaluate supplier ESG practices"},{"label":"Basic awareness","value":1,"description":"We consider ESG informally when selecting suppliers"},{"label":"Supplier code","value":2,"description":"Formal supplier code of conduct with ESG requirements"},{"label":"Active monitoring","value":3,"description":"Regular supplier assessments, audits, and improvement programs"},{"label":"Full visibility","value":4,"description":"Comprehensive supply chain ESG mapping with public reporting"}]'::jsonb, 'active'),
  ('s-supply-2', 'social', 'supply-chain-responsibility', 'Supply Chain Responsibility', 'Has your organization conducted human rights due diligence across your value chain?', NULL, 2, 15, '[{"label":"No due diligence","value":0,"description":"Human rights risks have not been assessed"},{"label":"Policy only","value":1,"description":"We have a human rights policy but limited implementation"},{"label":"Risk assessment","value":2,"description":"Initial human rights risk assessment completed"},{"label":"Ongoing process","value":3,"description":"Regular HRDD process with remediation mechanisms"},{"label":"Comprehensive HRDD","value":4,"description":"Full due diligence aligned with UN Guiding Principles"}]'::jsonb, 'active'),
  ('s-community-1', 'social', 'community-engagement', 'Community Engagement', 'How does your organization engage with and contribute to local communities?', NULL, 1, 16, '[{"label":"No engagement","value":0,"description":"No formal community engagement"},{"label":"Ad hoc giving","value":1,"description":"Occasional charitable donations or volunteering"},{"label":"Structured program","value":2,"description":"Formal community investment program"},{"label":"Strategic partnerships","value":3,"description":"Long-term community partnerships aligned with business strategy"},{"label":"Shared value","value":4,"description":"Creating shared value with measurable community impact"}]'::jsonb, 'active'),
  ('s-community-2', 'social', 'community-engagement', 'Community Engagement', 'Does your organization engage stakeholders in identifying and addressing social impacts?', NULL, 1, 17, '[{"label":"No engagement","value":0,"description":"Stakeholders are not consulted on social impacts"},{"label":"Reactive only","value":1,"description":"We respond to concerns when raised"},{"label":"Periodic engagement","value":2,"description":"Regular stakeholder surveys or consultations"},{"label":"Collaborative approach","value":3,"description":"Active stakeholder dialogue with feedback integration"},{"label":"Co-creation","value":4,"description":"Stakeholders co-create social impact strategies with us"}]'::jsonb, 'active'),
  ('s-privacy-1', 'social', 'data-privacy', 'Data Privacy & Cybersecurity', 'How mature is your organization''s data privacy program?', NULL, 2, 18, '[{"label":"No program","value":0,"description":"No formal data privacy measures beyond basics"},{"label":"Legal compliance","value":1,"description":"Basic compliance with applicable privacy laws"},{"label":"Privacy program","value":2,"description":"Dedicated privacy program with policies and training"},{"label":"Privacy by design","value":3,"description":"Privacy embedded in product/service development"},{"label":"Certified & audited","value":4,"description":"Privacy certification (e.g., ISO 27701) with regular audits"}]'::jsonb, 'active'),
  ('s-privacy-2', 'social', 'data-privacy', 'Data Privacy & Cybersecurity', 'Does your organization have a cybersecurity risk management program?', NULL, 2, 19, '[{"label":"No program","value":0,"description":"No formal cybersecurity program"},{"label":"Basic measures","value":1,"description":"Standard IT security measures (firewalls, antivirus)"},{"label":"Risk-based approach","value":2,"description":"Formal cybersecurity program with risk assessments"},{"label":"Advanced program","value":3,"description":"Comprehensive program with incident response and regular testing"},{"label":"Certified & resilient","value":4,"description":"Certified (e.g., SOC 2, ISO 27001) with full cyber resilience"}]'::jsonb, 'active'),
  ('g-board-1', 'governance', 'board-structure', 'Board Structure & Independence', 'How is ESG oversight structured at the board level?', 'Board-level ESG oversight demonstrates strategic commitment to sustainability.', 3, 20, '[{"label":"No oversight","value":0,"description":"The board does not discuss ESG matters"},{"label":"Occasional discussion","value":1,"description":"ESG comes up occasionally in board meetings"},{"label":"Designated responsibility","value":2,"description":"A board member or committee has ESG responsibility"},{"label":"Dedicated committee","value":3,"description":"A dedicated ESG/sustainability committee exists"},{"label":"Fully integrated","value":4,"description":"ESG is integrated into all board decisions with expert members"}]'::jsonb, 'active'),
  ('g-board-2', 'governance', 'board-structure', 'Board Structure & Independence', 'Does your board include diverse representation and independent members?', NULL, 2, 21, '[{"label":"Not applicable / No board","value":0,"description":"No formal board or advisory body"},{"label":"Limited diversity","value":1,"description":"Board exists but lacks diversity or independence"},{"label":"Some diversity","value":2,"description":"Board has some diverse members and independent directors"},{"label":"Strong diversity","value":3,"description":"Board has meaningful diversity across multiple dimensions"},{"label":"Exemplary governance","value":4,"description":"Highly diverse, majority-independent board with regular evaluations"}]'::jsonb, 'active'),
  ('g-ethics-1', 'governance', 'ethics-compliance', 'Ethics & Anti-Corruption', 'Does your organization have a code of ethics and anti-corruption program?', NULL, 3, 22, '[{"label":"No code","value":0,"description":"No formal code of ethics or anti-corruption measures"},{"label":"Basic code","value":1,"description":"Written code of conduct but limited enforcement"},{"label":"Active program","value":2,"description":"Code of ethics with regular training and reporting channels"},{"label":"Comprehensive program","value":3,"description":"Strong ethics program with whistleblower protections"},{"label":"Industry benchmark","value":4,"description":"Best-practice ethics program with independent oversight"}]'::jsonb, 'active'),
  ('g-ethics-2', 'governance', 'ethics-compliance', 'Ethics & Anti-Corruption', 'How does your organization manage conflicts of interest and related-party transactions?', NULL, 2, 23, '[{"label":"No policy","value":0,"description":"No formal conflict of interest policy"},{"label":"Basic policy","value":1,"description":"Written policy but inconsistent enforcement"},{"label":"Active management","value":2,"description":"Conflict disclosure requirements with review process"},{"label":"Robust controls","value":3,"description":"Mandatory disclosure, independent review, and cooling-off periods"},{"label":"Full transparency","value":4,"description":"Complete public disclosure with independent audit"}]'::jsonb, 'active'),
  ('g-compensation-1', 'governance', 'executive-compensation', 'Executive Compensation', 'Is executive compensation linked to ESG or sustainability performance?', NULL, 2, 24, '[{"label":"No link","value":0,"description":"Executive pay has no ESG component"},{"label":"Under consideration","value":1,"description":"ESG-linked pay is being discussed or planned"},{"label":"Partial link","value":2,"description":"Some ESG metrics included in variable compensation"},{"label":"Meaningful link","value":3,"description":"Significant portion of variable pay tied to ESG targets"},{"label":"Fully integrated","value":4,"description":"ESG metrics are core to compensation across leadership"}]'::jsonb, 'active'),
  ('g-compensation-2', 'governance', 'executive-compensation', 'Executive Compensation', 'Does your organization disclose executive compensation ratios and practices?', NULL, 1, 25, '[{"label":"No disclosure","value":0,"description":"Compensation details are not shared"},{"label":"Legal minimum","value":1,"description":"Only legally required disclosures"},{"label":"Voluntary disclosure","value":2,"description":"Some voluntary disclosure beyond requirements"},{"label":"Detailed reporting","value":3,"description":"CEO-to-median pay ratio and compensation philosophy disclosed"},{"label":"Full transparency","value":4,"description":"Comprehensive disclosure with say-on-pay voting"}]'::jsonb, 'active'),
  ('g-shareholder-1', 'governance', 'shareholder-rights', 'Shareholder & Stakeholder Rights', 'How does your organization engage stakeholders in governance decisions?', NULL, 1, 26, '[{"label":"No engagement","value":0,"description":"Stakeholders have no voice in governance"},{"label":"Basic information","value":1,"description":"We share basic information but don''t seek input"},{"label":"Feedback channels","value":2,"description":"Formal channels for stakeholder feedback"},{"label":"Active engagement","value":3,"description":"Regular stakeholder engagement with input on key decisions"},{"label":"Shared governance","value":4,"description":"Stakeholder representation in governance structures"}]'::jsonb, 'active'),
  ('g-risk-1', 'governance', 'risk-management', 'Risk Management & Reporting', 'Has your organization integrated ESG risks into its enterprise risk management?', NULL, 3, 27, '[{"label":"Not integrated","value":0,"description":"ESG risks are not part of risk management"},{"label":"Awareness stage","value":1,"description":"Some awareness of ESG risks but no formal integration"},{"label":"Partially integrated","value":2,"description":"Key ESG risks identified and included in risk register"},{"label":"Fully integrated","value":3,"description":"ESG risks fully integrated with regular assessment"},{"label":"Strategic advantage","value":4,"description":"ESG risk management drives strategic decision-making"}]'::jsonb, 'active'),
  ('g-risk-2', 'governance', 'risk-management', 'Risk Management & Reporting', 'Does your organization conduct materiality assessments to identify priority ESG topics?', 'Materiality assessments identify which ESG issues matter most to your business and stakeholders.', 2, 28, '[{"label":"No assessment","value":0,"description":"We haven''t assessed ESG materiality"},{"label":"Informal","value":1,"description":"General sense of what matters but no formal process"},{"label":"Basic assessment","value":2,"description":"Initial materiality assessment completed"},{"label":"Double materiality","value":3,"description":"Assessment covers both impact and financial materiality"},{"label":"Ongoing process","value":4,"description":"Regular reassessment with stakeholder input and public disclosure"}]'::jsonb, 'active')
INSERT INTO esg_recommendations (id, subcategory, maturity_level, title, description, actions, related_links) VALUES
  ('carbon-emissions-minimal', 'carbon-emissions', 'minimal', 'Start Measuring Your Carbon Footprint', 'Understanding your emissions is the essential first step. Even a rough estimate gives you a baseline to work from.', '["Use a free carbon calculator to estimate your Scope 1 and 2 emissions","Identify your largest emission sources (energy, travel, logistics)","Designate someone to own carbon tracking going forward"]'::jsonb, '[{"label":"GHG Protocol Framework","href":"/frameworks/ghg-protocol"},{"label":"Carbon Accounting Tools","href":"/categories/carbon-accounting"}]'::jsonb),
  ('carbon-emissions-beginning', 'carbon-emissions', 'beginning', 'Formalize Your Emissions Tracking', 'Move from estimates to formal measurement. Structured data enables better decisions and target-setting.', '["Implement a carbon accounting tool for Scope 1 and 2 tracking","Begin identifying major Scope 3 emission categories","Set initial reduction targets with clear timelines"]'::jsonb, '[{"label":"Carbon Accounting Tools","href":"/categories/carbon-accounting"},{"label":"SBTi Framework","href":"/frameworks/sbti"}]'::jsonb),
  ('carbon-emissions-developing', 'carbon-emissions', 'developing', 'Expand Scope and Set Science-Based Targets', 'With solid Scope 1-2 data, expand to Scope 3 and align targets with climate science.', '["Extend measurement to key Scope 3 categories","Explore SBTi target validation","Develop a decarbonization roadmap with milestones"]'::jsonb, '[{"label":"SBTi Framework","href":"/frameworks/sbti"},{"label":"CDP Disclosure","href":"/frameworks/cdp"}]'::jsonb),
  ('carbon-emissions-strong', 'carbon-emissions', 'strong', 'Pursue Verification and Deep Decarbonization', 'Your tracking is strong. Focus on third-party verification and ambitious reduction strategies.', '["Obtain third-party verification for your emissions data","Set net-zero targets with interim milestones","Engage suppliers on Scope 3 reduction strategies"]'::jsonb, '[{"label":"Verification & Assurance","href":"/categories/verification"}]'::jsonb),
  ('carbon-emissions-leading', 'carbon-emissions', 'leading', 'Maintain Leadership and Innovate', 'You''re leading on carbon management. Continue innovating and help your industry raise the bar.', '["Share best practices through industry coalitions","Explore carbon removal and insetting strategies","Support policy advocacy for stronger climate action"]'::jsonb, '[]'::jsonb),
  ('energy-management-minimal', 'energy-management', 'minimal', 'Start Tracking Energy Use', 'Begin monitoring energy consumption to identify savings opportunities.', '["Collect energy bills and track monthly consumption","Identify your largest energy consumers (HVAC, lighting, equipment)","Conduct a basic energy walk-through or audit"]'::jsonb, '[]'::jsonb),
  ('energy-management-beginning', 'energy-management', 'beginning', 'Set Energy Efficiency Targets', 'With baseline data, start setting targets and making improvements.', '["Set annual energy reduction targets (e.g., 5% year-over-year)","Implement quick wins: LED lighting, smart thermostats, power management","Explore renewable energy procurement options"]'::jsonb, '[]'::jsonb),
  ('energy-management-developing', 'energy-management', 'developing', 'Invest in Renewables and Efficiency', 'Move beyond low-hanging fruit to systematic efficiency and renewable procurement.', '["Procure renewable energy through PPAs or green tariffs","Implement an energy management system","Set a renewable energy target (e.g., 50% by specific year)"]'::jsonb, '[]'::jsonb),
  ('energy-management-strong', 'energy-management', 'strong', 'Optimize and Certify Your Energy Program', 'Your energy program is mature. Consider certification and advanced optimization.', '["Pursue ISO 50001 energy management certification","Implement real-time energy monitoring and analytics","Explore on-site renewable generation"]'::jsonb, '[]'::jsonb),
  ('energy-management-leading', 'energy-management', 'leading', 'Lead the Energy Transition', 'You''re an energy leader. Help accelerate the broader transition.', '["Share your renewable energy journey publicly","Support emerging clean energy technologies","Help suppliers transition to renewable energy"]'::jsonb, '[]'::jsonb),
  ('waste-circular-economy-minimal', 'waste-circular-economy', 'minimal', 'Begin Waste Measurement', 'Start tracking waste generation to understand your footprint and identify reduction opportunities.', '["Conduct a waste audit to understand waste streams","Set up basic recycling infrastructure","Track total waste and diversion rates"]'::jsonb, '[]'::jsonb),
  ('waste-circular-economy-beginning', 'waste-circular-economy', 'beginning', 'Formalize Waste Reduction Efforts', 'Build on initial tracking with formal programs and targets.', '["Set waste reduction and diversion rate targets","Implement composting for organic waste if applicable","Train employees on proper waste sorting"]'::jsonb, '[]'::jsonb),
  ('waste-circular-economy-developing', 'waste-circular-economy', 'developing', 'Adopt Circular Economy Principles', 'Move beyond waste management to circular thinking in product and process design.', '["Assess products/services for circular design opportunities","Partner with waste-to-resource companies","Implement take-back or refurbishment programs"]'::jsonb, '[]'::jsonb),
  ('waste-circular-economy-strong', 'waste-circular-economy', 'strong', 'Scale Circular Practices', 'Expand circular economy practices across your value chain.', '["Set zero-waste-to-landfill targets","Integrate circular metrics into product development","Engage suppliers on packaging reduction"]'::jsonb, '[]'::jsonb),
  ('waste-circular-economy-leading', 'waste-circular-economy', 'leading', 'Pioneer Circular Innovation', 'You''re leading on circularity. Drive industry-wide transformation.', '["Publish your circular economy approach and results","Collaborate on industry circular economy standards","Invest in circular economy startups or innovations"]'::jsonb, '[]'::jsonb),
  ('water-resources-minimal', 'water-resources', 'minimal', 'Start Monitoring Water Usage', 'Understanding your water footprint is the first step toward stewardship.', '["Track total water consumption across facilities","Identify water-intensive operations","Assess whether you operate in water-stressed areas"]'::jsonb, '[]'::jsonb),
  ('water-resources-beginning', 'water-resources', 'beginning', 'Set Water Efficiency Targets', 'With baseline data, begin setting and working toward water efficiency improvements.', '["Set water reduction targets for key operations","Fix leaks and implement water-efficient fixtures","Evaluate water recycling opportunities"]'::jsonb, '[]'::jsonb),
  ('water-resources-developing', 'water-resources', 'developing', 'Implement Water Stewardship', 'Move to proactive water stewardship with supply chain considerations.', '["Conduct a detailed water risk assessment","Implement water recycling and reuse systems","Assess supply chain water risks using tools like WRI Aqueduct"]'::jsonb, '[]'::jsonb),
  ('water-resources-strong', 'water-resources', 'strong', 'Advance Water Leadership', 'Your water program is mature. Focus on broader watershed impact.', '["Engage in local watershed protection initiatives","Set context-based water targets aligned with local availability","Report on water through CDP Water Security questionnaire"]'::jsonb, '[]'::jsonb),
  ('water-resources-leading', 'water-resources', 'leading', 'Drive Water Positive Impact', 'You''re leading on water. Help others and expand your impact.', '["Work toward water-positive status","Support community water access programs","Advocate for water policy improvements"]'::jsonb, '[]'::jsonb),
  ('environmental-policy-minimal', 'environmental-policy', 'minimal', 'Develop an Environmental Policy', 'A formal policy signals commitment and provides a foundation for environmental management.', '["Draft a basic environmental policy statement","Get leadership endorsement and publish it","Identify key environmental regulations that apply to you"]'::jsonb, '[{"label":"ESG Glossary","href":"/glossary"},{"label":"Standards & Frameworks","href":"/categories/standards-frameworks"}]'::jsonb),
  ('environmental-policy-beginning', 'environmental-policy', 'beginning', 'Build Environmental Management Practices', 'Move from policy to practice with structured environmental management.', '["Assign environmental responsibilities to specific roles","Conduct a compliance gap analysis","Begin tracking key environmental metrics"]'::jsonb, '[]'::jsonb),
  ('environmental-policy-developing', 'environmental-policy', 'developing', 'Implement an Environmental Management System', 'Systematize your environmental management for consistency and improvement.', '["Implement a formal environmental management system","Conduct internal environmental audits","Begin public environmental reporting"]'::jsonb, '[{"label":"Reporting Software","href":"/categories/reporting-software"}]'::jsonb),
  ('environmental-policy-strong', 'environmental-policy', 'strong', 'Pursue Certification and Framework Alignment', 'Your EMS is solid. Seek external validation and align with reporting frameworks.', '["Pursue ISO 14001 certification","Align reporting with GRI or TCFD frameworks","Obtain third-party assurance for environmental data"]'::jsonb, '[{"label":"GRI Standards","href":"/frameworks/gri-standards"},{"label":"TCFD","href":"/frameworks/tcfd"}]'::jsonb),
  ('environmental-policy-leading', 'environmental-policy', 'leading', 'Set the Standard for Environmental Transparency', 'You''re a leader in environmental management. Help elevate industry standards.', '["Publish a comprehensive sustainability report annually","Participate in industry environmental working groups","Mentor other organizations on their environmental journey"]'::jsonb, '[]'::jsonb),
  ('labor-practices-minimal', 'labor-practices', 'minimal', 'Ensure Basic Labor Standards', 'Start with ensuring compliance and building a foundation for fair labor practices.', '["Audit current wages against living wage benchmarks","Ensure all employment contracts are clear and compliant","Set up a basic employee feedback mechanism"]'::jsonb, '[]'::jsonb),
  ('labor-practices-beginning', 'labor-practices', 'beginning', 'Invest in Employee Wellbeing', 'Go beyond compliance to create a workplace that supports employee wellbeing.', '["Develop competitive benefits packages","Implement health and safety training programs","Create channels for employee voice and feedback"]'::jsonb, '[]'::jsonb),
  ('labor-practices-developing', 'labor-practices', 'developing', 'Build a Best-Practice Workplace', 'Strengthen your employee value proposition and workplace culture.', '["Commit to living wages across all operations","Implement flexible working arrangements","Develop comprehensive wellness programs"]'::jsonb, '[]'::jsonb),
  ('labor-practices-strong', 'labor-practices', 'strong', 'Achieve Employer of Choice Status', 'Your practices are strong. Focus on recognition and continuous improvement.', '["Pursue workplace certifications (e.g., Great Place to Work)","Implement an OHS management system (e.g., ISO 45001)","Benchmark compensation against industry leaders"]'::jsonb, '[]'::jsonb),
  ('labor-practices-leading', 'labor-practices', 'leading', 'Lead on Fair Work Practices', 'You''re a workplace leader. Help raise standards across your industry.', '["Publish transparent workforce metrics and progress","Advocate for industry-wide labor standard improvements","Share best practices with peers and suppliers"]'::jsonb, '[]'::jsonb),
  ('diversity-equity-inclusion-minimal', 'diversity-equity-inclusion', 'minimal', 'Begin Your DEI Journey', 'Start with understanding your current state and making a commitment to change.', '["Collect baseline diversity data across the organization","Develop a DEI commitment statement from leadership","Provide foundational DEI awareness training"]'::jsonb, '[]'::jsonb),
  ('diversity-equity-inclusion-beginning', 'diversity-equity-inclusion', 'beginning', 'Formalize Your DEI Program', 'Move from awareness to action with structured DEI initiatives.', '["Set specific, measurable DEI goals","Review hiring processes for bias and barriers","Establish employee resource groups or affinity networks"]'::jsonb, '[]'::jsonb),
  ('diversity-equity-inclusion-developing', 'diversity-equity-inclusion', 'developing', 'Embed DEI in Operations', 'Integrate DEI into core business processes and decision-making.', '["Conduct regular pay equity analyses","Implement inclusive leadership development programs","Track and report on DEI metrics quarterly"]'::jsonb, '[]'::jsonb),
  ('diversity-equity-inclusion-strong', 'diversity-equity-inclusion', 'strong', 'Advance DEI Transparency', 'Your DEI program is maturing. Increase accountability through transparency.', '["Publish annual DEI report with metrics and progress","Conduct third-party pay equity audits","Set representation targets for leadership roles"]'::jsonb, '[]'::jsonb),
  ('diversity-equity-inclusion-leading', 'diversity-equity-inclusion', 'leading', 'Champion DEI Industry-Wide', 'You''re a DEI leader. Extend your impact beyond your organization.', '["Share DEI playbooks and learnings publicly","Support supplier diversity programs","Invest in community programs that advance equity"]'::jsonb, '[]'::jsonb),
  ('supply-chain-responsibility-minimal', 'supply-chain-responsibility', 'minimal', 'Map Your Supply Chain', 'Understanding your supply chain is essential for managing ESG risks.', '["Identify and map your key suppliers (Tier 1)","Develop a basic supplier code of conduct","Research common ESG risks in your industry''s supply chains"]'::jsonb, '[{"label":"Supply Chain ESG","href":"/categories/supply-chain"}]'::jsonb),
  ('supply-chain-responsibility-beginning', 'supply-chain-responsibility', 'beginning', 'Implement Supplier Standards', 'Formalize ESG expectations for your supply chain.', '["Roll out your supplier code of conduct to all key suppliers","Include ESG criteria in supplier selection processes","Begin screening suppliers for major ESG risks"]'::jsonb, '[]'::jsonb),
  ('supply-chain-responsibility-developing', 'supply-chain-responsibility', 'developing', 'Actively Monitor Supplier ESG', 'Move from requirements to active monitoring and engagement.', '["Conduct regular supplier ESG assessments or surveys","Implement corrective action processes for non-compliance","Extend visibility to Tier 2 suppliers"]'::jsonb, '[]'::jsonb),
  ('supply-chain-responsibility-strong', 'supply-chain-responsibility', 'strong', 'Build a Responsible Supply Chain Program', 'Your supply chain program is maturing. Deepen engagement and transparency.', '["Conduct on-site audits for high-risk suppliers","Collaborate with suppliers on improvement plans","Report publicly on supply chain ESG performance"]'::jsonb, '[]'::jsonb),
  ('supply-chain-responsibility-leading', 'supply-chain-responsibility', 'leading', 'Lead Supply Chain Transformation', 'You''re a supply chain leader. Drive systemic change.', '["Publish supply chain ESG mapping and progress","Participate in industry supply chain responsibility initiatives","Help key suppliers build their own ESG programs"]'::jsonb, '[]'::jsonb),
  ('community-engagement-minimal', 'community-engagement', 'minimal', 'Identify Community Connections', 'Start by understanding how your business interacts with and impacts local communities.', '["Map your key community stakeholders","Identify ways your business positively or negatively impacts the community","Start a small employee volunteering or giving program"]'::jsonb, '[]'::jsonb),
  ('community-engagement-beginning', 'community-engagement', 'beginning', 'Develop a Community Investment Strategy', 'Move from ad hoc efforts to structured community engagement.', '["Define focus areas for community investment","Set a budget or target for community giving","Partner with local nonprofits aligned with your business"]'::jsonb, '[]'::jsonb),
  ('community-engagement-developing', 'community-engagement', 'developing', 'Build Strategic Community Partnerships', 'Align community engagement with business strategy for greater impact.', '["Develop long-term community partnerships","Measure and report on community impact","Engage employees in skill-based volunteering"]'::jsonb, '[]'::jsonb),
  ('community-engagement-strong', 'community-engagement', 'strong', 'Create Shared Value', 'Your community program is strong. Focus on shared value creation.', '["Design programs that create business and social value simultaneously","Integrate community impact into business strategy","Include community stakeholders in materiality assessments"]'::jsonb, '[]'::jsonb),
  ('community-engagement-leading', 'community-engagement', 'leading', 'Lead on Community Impact', 'You''re a community engagement leader. Amplify your impact.', '["Publish impact reports with measurable community outcomes","Support community-led development initiatives","Advocate for policies that benefit communities"]'::jsonb, '[]'::jsonb),
  ('data-privacy-minimal', 'data-privacy', 'minimal', 'Establish Data Privacy Basics', 'Start with understanding your data and ensuring basic legal compliance.', '["Conduct a data inventory to understand what personal data you collect","Ensure compliance with applicable privacy laws (GDPR, CCPA, etc.)","Create a basic privacy policy and publish it"]'::jsonb, '[]'::jsonb),
  ('data-privacy-beginning', 'data-privacy', 'beginning', 'Build a Privacy Program', 'Move beyond compliance to a structured privacy program.', '["Designate a privacy lead or data protection officer","Implement data subject access request processes","Train all employees on data privacy basics"]'::jsonb, '[]'::jsonb),
  ('data-privacy-developing', 'data-privacy', 'developing', 'Embed Privacy by Design', 'Integrate privacy into your products, services, and processes.', '["Implement privacy impact assessments for new projects","Adopt privacy-by-design principles in product development","Enhance cybersecurity incident response capabilities"]'::jsonb, '[]'::jsonb),
  ('data-privacy-strong', 'data-privacy', 'strong', 'Achieve Privacy Excellence', 'Your privacy program is mature. Pursue certification and advanced controls.', '["Pursue ISO 27001 or SOC 2 certification","Conduct regular penetration testing and security audits","Implement advanced data protection technologies"]'::jsonb, '[]'::jsonb),
  ('data-privacy-leading', 'data-privacy', 'leading', 'Lead on Data Ethics', 'You''re a privacy leader. Advance data ethics and trust.', '["Develop and publish data ethics guidelines","Lead industry conversations on responsible data use","Support the development of AI governance frameworks"]'::jsonb, '[]'::jsonb),
  ('board-structure-minimal', 'board-structure', 'minimal', 'Establish Governance Foundations', 'Even small companies benefit from basic governance structures that include ESG.', '["Create an advisory board or formalize governance roles","Include ESG as a standing agenda item in leadership meetings","Identify who is responsible for sustainability decisions"]'::jsonb, '[]'::jsonb),
  ('board-structure-beginning', 'board-structure', 'beginning', 'Formalize ESG Governance', 'Strengthen ESG oversight with dedicated governance mechanisms.', '["Assign ESG oversight to a specific board member or leader","Ensure ESG is discussed at least quarterly at board level","Seek diverse perspectives in governance decisions"]'::jsonb, '[]'::jsonb),
  ('board-structure-developing', 'board-structure', 'developing', 'Build Dedicated ESG Oversight', 'Create dedicated structures for ESG governance and oversight.', '["Establish an ESG committee or working group","Recruit board members with ESG/sustainability expertise","Set board-level ESG targets and review progress regularly"]'::jsonb, '[]'::jsonb),
  ('board-structure-strong', 'board-structure', 'strong', 'Strengthen Board ESG Integration', 'Your governance is strong. Deepen ESG integration at the board level.', '["Integrate ESG into all major board decisions","Conduct board evaluations including ESG competency","Ensure board diversity across gender, ethnicity, skills, and experience"]'::jsonb, '[]'::jsonb),
  ('board-structure-leading', 'board-structure', 'leading', 'Model Exemplary ESG Governance', 'You''re a governance leader. Share your approach and continue innovating.', '["Publish your governance framework and ESG oversight structure","Mentor other organizations on ESG governance","Participate in governance standard-setting initiatives"]'::jsonb, '[]'::jsonb),
  ('ethics-compliance-minimal', 'ethics-compliance', 'minimal', 'Create a Code of Ethics', 'A code of ethics sets expectations and protects your business.', '["Draft a code of conduct covering key ethical standards","Communicate the code to all employees","Establish a way for employees to report concerns"]'::jsonb, '[]'::jsonb),
  ('ethics-compliance-beginning', 'ethics-compliance', 'beginning', 'Build an Ethics Program', 'Move from a written code to an active ethics program.', '["Implement regular ethics and compliance training","Create a confidential reporting mechanism (hotline or email)","Develop an anti-corruption and anti-bribery policy"]'::jsonb, '[]'::jsonb),
  ('ethics-compliance-developing', 'ethics-compliance', 'developing', 'Strengthen Ethics and Compliance', 'Enhance your program with monitoring and enforcement.', '["Implement whistleblower protections and non-retaliation policies","Conduct regular compliance audits","Track and report on ethics metrics (reports, investigations, outcomes)"]'::jsonb, '[]'::jsonb),
  ('ethics-compliance-strong', 'ethics-compliance', 'strong', 'Achieve Compliance Excellence', 'Your ethics program is robust. Focus on culture and continuous improvement.', '["Conduct independent ethics program reviews","Integrate ethics into performance evaluations","Benchmark against industry best practices"]'::jsonb, '[]'::jsonb),
  ('ethics-compliance-leading', 'ethics-compliance', 'leading', 'Lead on Business Ethics', 'You''re an ethics leader. Help raise standards across your industry.', '["Publish transparency reports on ethics and compliance","Participate in anti-corruption coalitions and initiatives","Support the development of industry ethics standards"]'::jsonb, '[]'::jsonb),
  ('executive-compensation-minimal', 'executive-compensation', 'minimal', 'Begin Linking Pay to ESG', 'Tying executive pay to ESG creates accountability and drives action.', '["Identify which ESG metrics matter most to your business","Discuss ESG-linked compensation with leadership","Review peer companies'' approaches to ESG in compensation"]'::jsonb, '[]'::jsonb),
  ('executive-compensation-beginning', 'executive-compensation', 'beginning', 'Design ESG Compensation Linkages', 'Start formally connecting executive pay to ESG performance.', '["Include at least one ESG metric in executive variable pay","Define clear measurement criteria for ESG targets","Communicate the rationale to stakeholders"]'::jsonb, '[]'::jsonb),
  ('executive-compensation-developing', 'executive-compensation', 'developing', 'Expand ESG-Linked Compensation', 'Broaden the ESG metrics in compensation and increase weighting.', '["Increase the number and weighting of ESG metrics in variable pay","Extend ESG-linked compensation below the C-suite","Report on ESG compensation linkages publicly"]'::jsonb, '[]'::jsonb),
  ('executive-compensation-strong', 'executive-compensation', 'strong', 'Optimize ESG Compensation Design', 'Your ESG compensation approach is strong. Refine and optimize.', '["Ensure ESG targets are ambitious yet achievable","Align ESG compensation metrics with long-term strategy","Seek external feedback on compensation design"]'::jsonb, '[]'::jsonb),
  ('executive-compensation-leading', 'executive-compensation', 'leading', 'Set the Standard for ESG-Linked Pay', 'You''re a leader in ESG compensation. Share your approach.', '["Publish detailed ESG compensation methodology","Present your approach at governance conferences","Help develop industry guidance on ESG-linked pay"]'::jsonb, '[]'::jsonb),
  ('shareholder-rights-minimal', 'shareholder-rights', 'minimal', 'Open Stakeholder Communication', 'Start by creating channels for stakeholder voice and feedback.', '["Identify your key stakeholder groups","Create basic communication channels (website, email)","Share key business updates with stakeholders regularly"]'::jsonb, '[]'::jsonb),
  ('shareholder-rights-beginning', 'shareholder-rights', 'beginning', 'Formalize Stakeholder Engagement', 'Build structured approaches to stakeholder engagement.', '["Develop a stakeholder engagement plan","Implement feedback mechanisms (surveys, meetings)","Respond to stakeholder inquiries in a timely manner"]'::jsonb, '[]'::jsonb),
  ('shareholder-rights-developing', 'shareholder-rights', 'developing', 'Deepen Stakeholder Participation', 'Move from informing to genuinely involving stakeholders.', '["Include stakeholder perspectives in materiality assessments","Create advisory panels with stakeholder representation","Report on how stakeholder feedback influences decisions"]'::jsonb, '[]'::jsonb),
  ('shareholder-rights-strong', 'shareholder-rights', 'strong', 'Build Stakeholder Trust', 'Your engagement is strong. Deepen trust through transparency.', '["Implement say-on-pay or equivalent stakeholder voting","Publish stakeholder engagement reports","Address material stakeholder concerns publicly"]'::jsonb, '[]'::jsonb),
  ('shareholder-rights-leading', 'shareholder-rights', 'leading', 'Lead on Stakeholder Governance', 'You''re a leader in stakeholder governance. Continue innovating.', '["Include stakeholder representatives in governance structures","Publish comprehensive stakeholder engagement impact reports","Advocate for stakeholder capitalism principles"]'::jsonb, '[]'::jsonb),
  ('risk-management-minimal', 'risk-management', 'minimal', 'Start Identifying ESG Risks', 'Understanding your ESG risk exposure is critical for long-term resilience.', '["List your top 5 potential ESG risks (climate, regulation, reputation, etc.)","Discuss ESG risks in leadership meetings","Review industry ESG risk reports for common threats"]'::jsonb, '[{"label":"TCFD Framework","href":"/frameworks/tcfd"},{"label":"ESG Glossary","href":"/glossary"}]'::jsonb),
  ('risk-management-beginning', 'risk-management', 'beginning', 'Formalize ESG Risk Assessment', 'Move from awareness to structured ESG risk management.', '["Include ESG risks in your risk register","Assign ownership for key ESG risks","Begin scenario analysis for climate-related risks"]'::jsonb, '[{"label":"TCFD Framework","href":"/frameworks/tcfd"}]'::jsonb),
  ('risk-management-developing', 'risk-management', 'developing', 'Integrate ESG into Enterprise Risk Management', 'Fully integrate ESG risks into your overall risk management framework.', '["Conduct a formal materiality assessment","Integrate ESG risks into enterprise risk management processes","Begin reporting on ESG risks aligned with TCFD recommendations"]'::jsonb, '[{"label":"TCFD Framework","href":"/frameworks/tcfd"},{"label":"ISSB Standards","href":"/frameworks/issb-ifrs-s1-s2"}]'::jsonb),
  ('risk-management-strong', 'risk-management', 'strong', 'Advance Strategic ESG Risk Management', 'Your ESG risk management is mature. Use it as a strategic advantage.', '["Conduct double materiality assessments (impact + financial)","Implement quantitative climate scenario analysis","Align risk disclosure with ISSB or ESRS standards"]'::jsonb, '[]'::jsonb),
  ('risk-management-leading', 'risk-management', 'leading', 'Lead on ESG Risk Innovation', 'You''re a leader in ESG risk management. Drive industry advancement.', '["Publish thought leadership on ESG risk management","Participate in risk management standard-setting","Help suppliers and partners build their ESG risk capabilities"]'::jsonb, '[]'::jsonb)
INSERT INTO esg_resources (id, category_slug, category_title, category_description, name, description, type, cost, link, is_internal, sort_order) VALUES
  ('self-assessment-0', 'self-assessment', 'Free ESG Self-Assessment Tools', 'Online tools that let you evaluate your organization''s ESG performance for free or at low cost.', 'ESGsource ESG Score', 'Our own 30-question assessment covering Environmental, Social, and Governance with personalized recommendations and downloadable report.', 'Self-Assessment', 'Free', '/score', TRUE, 0),
  ('self-assessment-1', 'self-assessment', 'Free ESG Self-Assessment Tools', 'Online tools that let you evaluate your organization''s ESG performance for free or at low cost.', 'Esgrid Free ESG Assessment', '30-minute self-assessment questionnaire providing sustainability insights and recommendations. No expertise required.', 'Self-Assessment', 'Free', 'https://esgrid.com/esg-health', FALSE, 1),
  ('self-assessment-2', 'self-assessment', 'Free ESG Self-Assessment Tools', 'Online tools that let you evaluate your organization''s ESG performance for free or at low cost.', 'Inogen Alliance ESG Tool', 'Free global ESG pre-screening tool with industry-adapted smart questionnaire, AI-powered reports, and benchmarking insights.', 'Self-Assessment', 'Free', 'https://www.inogenalliance.com/esg-assessment-tool', FALSE, 2),
  ('self-assessment-3', 'self-assessment', 'Free ESG Self-Assessment Tools', 'Online tools that let you evaluate your organization''s ESG performance for free or at low cost.', 'HPC AG ESG Assessment', 'Free industry-adapted ESG assessment with AI-powered summaries, performance scoring, and benchmarking capabilities.', 'Self-Assessment', 'Free', 'https://hpc.ag/en/esg-assessment-tool/', FALSE, 3),
  ('self-assessment-4', 'self-assessment', 'Free ESG Self-Assessment Tools', 'Online tools that let you evaluate your organization''s ESG performance for free or at low cost.', 'Deloitte Sustainability SelfAssess', 'Assessment across 8 main sustainability areas, tailored for companies at any stage of their sustainability journey.', 'Self-Assessment', 'Free', 'https://www.deloitte.com/us/en/services/audit/articles/esg-materiality-assessment.html', FALSE, 4),
  ('self-assessment-5', 'self-assessment', 'Free ESG Self-Assessment Tools', 'Online tools that let you evaluate your organization''s ESG performance for free or at low cost.', 'Wolters Kluwer ESG Tool', 'Accessible online self-assessment questionnaire for evaluating your organization''s ESG position.', 'Self-Assessment', 'Free', 'https://esgselfassesment.wolterskluwer.com/en', FALSE, 5),
  ('self-assessment-6', 'self-assessment', 'Free ESG Self-Assessment Tools', 'Online tools that let you evaluate your organization''s ESG performance for free or at low cost.', 'Bolder ESG Self-Assessment', 'Survey that determines your ESG strategy development level and provides foundational recommendations.', 'Self-Assessment', 'Free', 'https://boldergroup.com/esg-self-assessment-survey/', FALSE, 6),
  ('marketplaces-0', 'marketplaces', 'ESG Consultant & Vendor Marketplaces', 'Directories and platforms where you can find ESG consultants, software vendors, and service providers.', 'ESGsource Directory', 'Our curated directory of 50+ ESG organizations including consultants, data providers, software vendors, and standard bodies.', 'Directory', 'Free', '/directory', TRUE, 0),
  ('marketplaces-1', 'marketplaces', 'ESG Consultant & Vendor Marketplaces', 'Directories and platforms where you can find ESG consultants, software vendors, and service providers.', 'ESGsource Consultant Finder', 'Browse ESG consulting and advisory firms filtered by specialty, company size served, and geography.', 'Directory', 'Free', '/directory/consultants', TRUE, 1),
  ('marketplaces-2', 'marketplaces', 'ESG Consultant & Vendor Marketplaces', 'Directories and platforms where you can find ESG consultants, software vendors, and service providers.', 'KnowESG Solutions Directory', '850+ ESG providers across 11 categories including carbon accounting, reporting software, sustainability consulting, and more. Filter by framework, geography, and company size.', 'Marketplace', 'Free to browse', 'https://knowesg.com/solutions', FALSE, 2),
  ('frameworks-0', 'frameworks', 'ESG Frameworks & Standards', 'Major frameworks and standards that guide ESG reporting, measurement, and disclosure.', 'ESGsource Framework Guide', 'Our comprehensive guide to 19+ ESG frameworks including GRI, ISSB, CSRD, TCFD, CDP, GHG Protocol, SBTi, and more.', 'Guide', 'Free', '/frameworks', TRUE, 0),
  ('frameworks-1', 'frameworks', 'ESG Frameworks & Standards', 'Major frameworks and standards that guide ESG reporting, measurement, and disclosure.', 'GRI Standards', 'The world''s most widely used sustainability reporting standards. Focus on impact materiality — your organization''s most significant impacts on environment and people.', 'Standard', 'Free to access', 'https://www.globalreporting.org/standards/', FALSE, 1),
  ('frameworks-2', 'frameworks', 'ESG Frameworks & Standards', 'Major frameworks and standards that guide ESG reporting, measurement, and disclosure.', 'SASB Standards (ISSB)', '77 industry-specific sustainability disclosure standards identifying the most financially material ESG issues per industry.', 'Standard', 'Free to access', 'https://sasb.ifrs.org/standards/', FALSE, 2),
  ('frameworks-3', 'frameworks', 'ESG Frameworks & Standards', 'Major frameworks and standards that guide ESG reporting, measurement, and disclosure.', 'TCFD Recommendations', 'Framework for climate-related financial disclosures covering governance, strategy, risk management, and metrics/targets.', 'Framework', 'Free', 'https://www.fsb-tcfd.org/', FALSE, 3),
  ('frameworks-4', 'frameworks', 'ESG Frameworks & Standards', 'Major frameworks and standards that guide ESG reporting, measurement, and disclosure.', 'GHG Protocol', 'The global standard for measuring and managing greenhouse gas emissions across Scope 1, 2, and 3.', 'Standard', 'Free', 'https://ghgprotocol.org/', FALSE, 4),
  ('frameworks-5', 'frameworks', 'ESG Frameworks & Standards', 'Major frameworks and standards that guide ESG reporting, measurement, and disclosure.', 'Science Based Targets initiative (SBTi)', 'Framework for setting corporate emissions reduction targets in line with climate science. Target validation available.', 'Framework', 'Free guidance / Paid validation', 'https://sciencebasedtargets.org/', FALSE, 5),
  ('regulatory-0', 'regulatory', 'Regulatory Guides & Updates', 'Stay current with ESG regulations and compliance requirements across regions.', 'EU CSRD Overview (European Commission)', 'Official European Commission page on the Corporate Sustainability Reporting Directive, including scope, timelines, and ESRS standards.', 'Regulation', 'Free', 'https://finance.ec.europa.eu/capital-markets-union-and-financial-markets/company-reporting-and-auditing/company-reporting/corporate-sustainability-reporting_en', FALSE, 0),
  ('regulatory-1', 'regulatory', 'Regulatory Guides & Updates', 'Stay current with ESG regulations and compliance requirements across regions.', 'ESGsource Regulators & Policy Guide', 'Our guide to the key regulatory bodies and policy frameworks shaping ESG requirements globally.', 'Guide', 'Free', '/categories/regulators', TRUE, 1),
  ('regulatory-2', 'regulatory', 'Regulatory Guides & Updates', 'Stay current with ESG regulations and compliance requirements across regions.', 'EU VSME Standard', 'The Voluntary Standard for SMEs — the EU''s recommended proportionate sustainability reporting standard for smaller companies. Effective July 2025.', 'Standard', 'Free', 'https://www.efrag.org/en/projects/vsme-standard/concluded', FALSE, 2),
  ('learning-0', 'learning', 'ESG Learning & Training', 'Educational resources to build ESG knowledge for you and your team.', 'ESGsource ESG Glossary', '47+ ESG terms explained in plain language, from Scope 1 emissions to double materiality.', 'Reference', 'Free', '/glossary', TRUE, 0),
  ('learning-1', 'learning', 'ESG Learning & Training', 'Educational resources to build ESG knowledge for you and your team.', 'ESGsource Free Training Programs', 'Curated collection of free ESG learning resources, certifications, and training programs from leading providers.', 'Training', 'Free', '/careers-training/free-trainings', TRUE, 1),
  ('learning-2', 'learning', 'ESG Learning & Training', 'Educational resources to build ESG knowledge for you and your team.', 'ESGsource Certifications Guide', 'Browse ESG certifications and credential programs to advance your sustainability expertise.', 'Guide', 'Free to browse', '/careers-training/certifications', TRUE, 2)
INSERT INTO site_settings (key, value, group_name) VALUES
  ('smb_esg_content', '{"hero":{"title":"ESG for Small & Medium Businesses","subtitle":"Most ESG regulations target large corporations — but smaller companies have the most to gain from embracing sustainability early. Here''s why and how."},"stats":[{"value":"72%","label":"of the global workforce will be Millennials and Gen Z by 2029 — generations that prioritize sustainable employers"},{"value":"10%+","label":"premium consumers are willing to pay for products from sustainable brands"},{"value":"85%","label":"of companies removed from EU CSRD scope after Dec 2025 threshold changes — proving most SMBs aren''t legally required to report"},{"value":"$57B","label":"projected sustainability consulting market by 2026, showing massive corporate demand"}],"whyItMatters":{"title":"Why ESG Matters for Small Businesses","intro":"Even though mandatory ESG reporting targets large organizations, smaller companies face growing indirect pressure — and have significant upside from voluntary adoption.","reasons":[{"title":"Supply Chain Requirements","icon":"chain","description":"Large corporations increasingly require ESG compliance from their suppliers. If you sell to enterprise customers, demonstrating ESG practices can be the difference between winning and losing contracts.","detail":"Companies reporting under EU CSRD must disclose supply chain ESG impacts, which flows down to their SMB suppliers as due diligence requirements."},{"title":"Talent Attraction & Retention","icon":"people","description":"Younger workers prioritize employers with strong sustainability commitments. ESG-friendly companies have a competitive advantage in the talent market.","detail":"Studies show top employers have significantly higher ESG scores, and satisfied employees at ESG-committed companies work harder and stay longer."},{"title":"Customer & Consumer Preferences","icon":"heart","description":"Consumers — especially Gen Z — increasingly prefer sustainable brands and are willing to pay a premium for them.","detail":"This isn''t just B2C: B2B buyers increasingly evaluate vendors on sustainability criteria as part of procurement processes."},{"title":"Investment & Financing Access","icon":"trending","description":"SMBs embracing ESG are more likely to attract sustainability-focused investors and access better financing terms.","detail":"Green loans, sustainability-linked credit facilities, and ESG-focused investment funds are growing rapidly, and many prioritize companies with demonstrated ESG practices."},{"title":"Risk Management","icon":"shield","description":"Proactive ESG management helps identify and mitigate risks before they become crises — from regulatory changes to reputational damage.","detail":"Climate risks, labor disputes, data breaches, and governance failures can disproportionately impact smaller companies that lack the resources to recover."},{"title":"Competitive Advantage & Agility","icon":"bolt","description":"SMBs can implement ESG changes faster than large corporations. Early adoption positions you ahead of competitors when requirements tighten.","detail":"Your agility and innovative strength as a smaller company enables early-mover advantage that larger, slower-moving organizations can''t match."}]},"regulations":{"title":"ESG Regulations: What Actually Applies to You?","intro":"The good news: most mandatory ESG regulations don''t apply to small businesses. The important news: that''s changing, and voluntary action now pays dividends later.","frameworks":[{"name":"EU CSRD","region":"European Union","thresholds":"1,000+ employees AND €450M+ net turnover (both required)","impact":"Most SMBs are exempt from mandatory reporting, but may face indirect requirements from enterprise customers in their supply chain.","status":"Active — revised thresholds effective Dec 2025"},{"name":"SEC Climate Rules","region":"United States","thresholds":"SEC-registered public companies","impact":"Currently stayed pending litigation. SEC ended its defense in March 2025. Rules remain uncertain.","status":"On hold"},{"name":"UK SDR","region":"United Kingdom","thresholds":"Financial services firms initially; expanding","impact":"Anti-greenwashing rules apply broadly. Product labeling requirements for investment products.","status":"Active"}],"voluntaryFrameworks":[{"name":"EU VSME (Voluntary Standard for SMEs)","description":"Officially recommended by the EU Commission (July 2025). Designed specifically for smaller companies to do meaningful sustainability reporting without the full ESRS burden. A scaled, proportionate approach.","link":"/frameworks"},{"name":"ISO 26000 (Social Responsibility)","description":"A voluntary guideline (not certifiable) applicable to organizations of any size. Provides flexible, non-prescriptive guidance on social responsibility best practices.","link":"/glossary"},{"name":"B Corp Certification","description":"A popular certification for businesses meeting high standards of social and environmental performance, accountability, and transparency. Particularly well-suited for SMBs.","link":"/directory"},{"name":"UN Global Compact","description":"A voluntary initiative with 10 principles covering human rights, labor, environment, and anti-corruption. Open to companies of any size with annual reporting requirements.","link":"/frameworks"}]},"roadmap":{"title":"Getting Started: A 5-Step ESG Roadmap","intro":"You don''t need a million-dollar budget or a dedicated sustainability team. Start where you are and build incrementally.","steps":[{"number":1,"title":"Assess Where You Stand","description":"Take our free ESG Score Assessment to understand your current position across Environmental, Social, and Governance dimensions.","timeframe":"1 day","cta":{"label":"Take the Assessment","href":"/score"}},{"number":2,"title":"Identify What Matters Most","description":"Focus on the ESG topics most relevant to your industry and stakeholders. Not everything matters equally — prioritize based on your business context and the scores from your assessment.","timeframe":"1-2 weeks"},{"number":3,"title":"Set Simple, Measurable Goals","description":"Pick 3-5 ESG priorities and set specific, time-bound targets. Start with low-hanging fruit: energy efficiency, basic diversity metrics, governance documentation.","timeframe":"1 month"},{"number":4,"title":"Implement and Track","description":"Put plans into action. Use free tools and frameworks to track progress. Engage employees — many ESG improvements come from changing daily practices.","timeframe":"Ongoing"},{"number":5,"title":"Communicate Your Progress","description":"Share what you''re doing — with customers, employees, investors, and your community. Transparency builds trust even when you''re early in your journey.","timeframe":"Quarterly","cta":{"label":"Explore Reporting Frameworks","href":"/frameworks"}}]},"myths":{"title":"ESG Myths for Small Companies — Debunked","items":[{"myth":"ESG is only for big companies","reality":"ESG regulations may target large companies, but the business benefits — talent, customers, financing, risk management — apply to companies of every size. Early adopters gain competitive advantage."},{"myth":"It''s too expensive for a small company","reality":"Many ESG improvements actually save money (energy efficiency, waste reduction). Free tools and frameworks like VSME and our assessment tool make getting started essentially free."},{"myth":"You need a sustainability team","reality":"Start by assigning ESG as a part-time responsibility to an existing team member. Many successful SMB ESG programs are run by operations, HR, or finance leads as part of their existing role."},{"myth":"ESG is just greenwashing","reality":"Done authentically with measurable goals and honest reporting, ESG creates real value. The key is to be genuine about where you are and transparent about your progress."},{"myth":"Customers and investors don''t care about SMB sustainability","reality":"Enterprise buyers increasingly require supplier ESG compliance. ESG-focused investors and lenders specifically seek smaller companies with strong sustainability practices."},{"myth":"You have to do everything at once","reality":"Start with what''s most material to your business. A focused approach on 3-5 priorities is far more effective than trying to address everything simultaneously."}]}}'::jsonb, 'content_pages')
