-- Seed data for assessment, resources, and config tables
-- Generated from JSON data files

BEGIN;

-- =============================================================================
-- 1. Assessment Industries
-- =============================================================================

ON CONFLICT (id) DO UPDATE SET value = EXCLUDED.value, label = EXCLUDED.label, sort_order = EXCLUDED.sort_order;

-- =============================================================================
-- 2. Assessment Regions
-- =============================================================================

ON CONFLICT (id) DO UPDATE SET value = EXCLUDED.value, label = EXCLUDED.label, sort_order = EXCLUDED.sort_order;

-- =============================================================================
-- 3. Assessment Questions
-- =============================================================================

ON CONFLICT (id) DO UPDATE SET pillar = EXCLUDED.pillar, subcategory = EXCLUDED.subcategory, subcategory_label = EXCLUDED.subcategory_label, text = EXCLUDED.text, help_text = EXCLUDED.help_text, weight = EXCLUDED.weight, sort_order = EXCLUDED.sort_order, options = EXCLUDED.options, status = EXCLUDED.status;

-- =============================================================================
-- 4. ESG Recommendations
-- =============================================================================

ON CONFLICT (id) DO UPDATE SET subcategory = EXCLUDED.subcategory, maturity_level = EXCLUDED.maturity_level, title = EXCLUDED.title, description = EXCLUDED.description, actions = EXCLUDED.actions, related_links = EXCLUDED.related_links;

-- =============================================================================
-- 5. ESG Resources
-- =============================================================================

ON CONFLICT (id) DO UPDATE SET category_slug = EXCLUDED.category_slug, category_title = EXCLUDED.category_title, category_description = EXCLUDED.category_description, name = EXCLUDED.name, description = EXCLUDED.description, type = EXCLUDED.type, cost = EXCLUDED.cost, link = EXCLUDED.link, is_internal = EXCLUDED.is_internal, sort_order = EXCLUDED.sort_order;

-- =============================================================================
-- 6. SMB ESG Content (site_settings)
-- =============================================================================

ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value, group_name = EXCLUDED.group_name;

-- =============================================================================
-- 7. Brand Guide (site_settings)
-- =============================================================================

UPDATE site_settings SET value = '{"brandName":"ESGsource","tagline":"Navigate the ESG Ecosystem","voice":{"tone":"Professional, authoritative, yet approachable","personality":"Trusted advisor who simplifies complexity","doList":["Use clear, jargon-free language when possible","Back claims with data or sources","Be inclusive of all ESG experience levels","Use active voice"],"dontList":["Don''t use overly promotional language","Don''t make unsubstantiated ESG claims","Avoid greenwashing terminology","Don''t use excessive jargon without explanation"]},"contentGuidelines":{"titleFormat":"{Topic} | {Context} — {Benefit}","metaDescriptionLength":{"min":120,"max":160},"headingStructure":"Always use H1 → H2 → H3 hierarchy, never skip levels","imageRequirements":"All images must have descriptive alt text. Use WebP format. Max 500KB.","ctaStyle":"Action-oriented verbs: Explore, Compare, Discover, Find","internalLinkingRules":"Link to at least 2 related pages per content piece"},"seoRules":{"titleMaxLength":60,"descriptionMaxLength":160,"focusKeywordRequired":true,"minWordCount":300,"maxReadingLevel":"Grade 9"},"trackingRequirements":{"requiredPixels":["ga4"],"eventTracking":{"required":["page_view","search","click_outbound","form_submit"],"recommended":["view_item","add_to_wishlist","share"]}}}'::jsonb WHERE key = 'brand_guide';

-- =============================================================================
-- 8. Entity Source Map
-- =============================================================================

ON CONFLICT (id) DO UPDATE SET entity_slug = EXCLUDED.entity_slug, source_name = EXCLUDED.source_name, source_url = EXCLUDED.source_url, search_query_footprint = EXCLUDED.search_query_footprint, app_store_id = EXCLUDED.app_store_id;

-- =============================================================================
-- 9. Navigation (site_settings)
-- =============================================================================

UPDATE site_settings SET value = '[{"label":"Ecosystem","href":"/ecosystem","megaMenu":{"columns":[{"heading":null,"items":[{"label":"Ecosystem Map","href":"/ecosystem","description":"Interactive visual of the ESG landscape","icon":"map"},{"label":"Directory","href":"/directory","description":"Browse 50+ ESG entities and vendors","icon":"building"},{"label":"Find a Consultant","href":"/directory/consultants","description":"ESG consulting and advisory firms","icon":"people"}]}]}},{"label":"Knowledge","href":"/categories","megaMenu":{"columns":[{"heading":"Rules & Standards","layerColor":"rules","items":[{"label":"Standards & Frameworks","href":"/categories/standards-frameworks"},{"label":"Regulators & Policy","href":"/categories/regulators"}]},{"heading":"Data & Measurement","layerColor":"data","items":[{"label":"ESG Data & Ratings","href":"/categories/esg-data-ratings"},{"label":"Data Infrastructure","href":"/categories/data-infrastructure"}]},{"heading":"Implementation & Services","layerColor":"impl","items":[{"label":"Reporting Software","href":"/categories/reporting-software"},{"label":"Carbon Accounting","href":"/categories/carbon-accounting"},{"label":"Supply Chain ESG","href":"/categories/supply-chain"},{"label":"Consulting","href":"/categories/consulting"},{"label":"Verification","href":"/categories/verification"}]},{"heading":"Frameworks","items":[{"label":"GRI Standards","href":"/frameworks/gri-standards"},{"label":"ISSB (IFRS S1/S2)","href":"/frameworks/issb-ifrs-s1-s2"},{"label":"EU CSRD","href":"/frameworks/eu-csrd"},{"label":"TCFD","href":"/frameworks/tcfd"},{"label":"GHG Protocol","href":"/frameworks/ghg-protocol"},{"label":"SBTi","href":"/frameworks/sbti"}],"viewAllLink":{"label":"View all 19 frameworks","href":"/frameworks"}},{"heading":"Glossary","items":[{"label":"ESG Glossary","href":"/glossary","description":"47 ESG terms explained","icon":"book"}]}]}},{"label":"Tools","href":"/find","megaMenu":{"columns":[{"heading":"Assess & Find","items":[{"label":"ESG Score Assessment","href":"/score","description":"Get your free ESG score in 10 minutes","icon":"chart"},{"label":"Find a Solution","href":"/find","description":"Get matched to the right ESG tools","icon":"search"},{"label":"Compare","href":"/compare","description":"Side-by-side comparison of providers","icon":"columns"}]},{"heading":"Resources","items":[{"label":"ESG for Small Business","href":"/small-business","description":"Guide for SMBs starting their ESG journey","icon":"building"},{"label":"Resources & Tools","href":"/resources","description":"Free tools, frameworks, and guides","icon":"book"}]}]}},{"label":"Careers & Training","href":"/careers-training","megaMenu":{"columns":[{"heading":"Learn","items":[{"label":"Certifications","href":"/careers-training/certifications"},{"label":"Training Programs","href":"/careers-training/trainings"},{"label":"Free Trainings","href":"/careers-training/free-trainings"}]},{"heading":"Career","items":[{"label":"Career Paths","href":"/careers-training/roles"},{"label":"Providers","href":"/careers-training/providers"}]},{"heading":"Work","items":[{"label":"Jobs","href":"/careers-training/jobs"}]}]}},{"label":"About","href":"/about"}]'::jsonb WHERE key = 'navigation_primary';

UPDATE site_settings SET value = '[{"heading":"Categories","links":[{"label":"Standards & Frameworks","href":"/categories/standards-frameworks"},{"label":"Regulators & Policy","href":"/categories/regulators"},{"label":"ESG Data & Ratings","href":"/categories/esg-data-ratings"},{"label":"Data Infrastructure","href":"/categories/data-infrastructure"},{"label":"Reporting Software","href":"/categories/reporting-software"},{"label":"Carbon Accounting","href":"/categories/carbon-accounting"},{"label":"Supply Chain ESG","href":"/categories/supply-chain"},{"label":"Consulting","href":"/categories/consulting"},{"label":"Verification","href":"/categories/verification"}]},{"heading":"Frameworks","links":[{"label":"GRI Standards","href":"/frameworks/gri-standards"},{"label":"ISSB (IFRS S1/S2)","href":"/frameworks/issb-ifrs-s1-s2"},{"label":"EU CSRD","href":"/frameworks/eu-csrd"},{"label":"TCFD","href":"/frameworks/tcfd"},{"label":"GHG Protocol","href":"/frameworks/ghg-protocol"},{"label":"SBTi","href":"/frameworks/sbti"}]},{"heading":"Careers & Training","links":[{"label":"Certifications","href":"/careers-training/certifications"},{"label":"Training Programs","href":"/careers-training/trainings"},{"label":"Free Trainings","href":"/careers-training/free-trainings"},{"label":"Career Paths","href":"/careers-training/roles"},{"label":"Providers","href":"/careers-training/providers"},{"label":"Jobs","href":"/careers-training/jobs"}]},{"heading":"Tools & Resources","links":[{"label":"ESG Score Assessment","href":"/score"},{"label":"Solution Finder","href":"/find"},{"label":"Compare Tool","href":"/compare"},{"label":"ESG for Small Business","href":"/small-business"},{"label":"Resources & Tools","href":"/resources"},{"label":"Find a Consultant","href":"/directory/consultants"},{"label":"Vendor Directory","href":"/directory"},{"label":"Glossary","href":"/glossary"},{"label":"Ecosystem Map","href":"/ecosystem"}]},{"heading":"About","links":[{"label":"About ESGsource","href":"/about"},{"label":"Privacy Policy","href":"/privacy"},{"label":"Terms of Use","href":"/terms"}]}]'::jsonb WHERE key = 'footer_sections';

COMMIT;
